function getGraphDetails(input) {
    const indegrees = {}
    const graph = {}

    for (const row of input) {
        for (let i = 0; i < row.length - 1; i++) {
            const src = row[i]
            const dst = row[i + 1]

            if (!(src in indegrees)) {
                indegrees[src] = 0
                graph[src] = []
            }

            if (!(dst in indegrees)) {
                indegrees[dst] = 0
                graph[dst] = []
            }

            graph[src].push(dst)
            indegrees[dst] += 1
        }
    }

    return { indegrees, graph }
}

function getLongestChainLength(input) {
    const { indegrees, graph } = getGraphDetails(input)

    const q = []
    const nextLvl = []

    for (const [node, indegree] of Object.entries(indegrees)) {
        if (indegree === 0) {
            q.push(node)
        }
    }

    let maxChainLen = 0

    while (q.length > 0) {
        const node = q.shift()
        const parentNodes = graph[node]

        for (const parentNode of parentNodes) {
            indegrees[parentNode] -= 1

            if (indegrees[parentNode] === 0) {
                nextLvl.push(parentNode)
            }
        }

        if (q.length === 0) {
            maxChainLen += 1
            q.push(...nextLvl)
            nextLvl.length = 0
        }
    }

    return maxChainLen
}
