DFS Solution (DFS version of Topological Sort)
public class TopSort {

    public String solution(char input[][]){

        Map<Character,List<Character>> graph = new HashMap<>();


        for(char in[]:input){
            for(int i=0;i<in.length-1;++i){
                List<Character> u = graph.getOrDefault(in[i], new ArrayList<>());
                List<Character> v = graph.getOrDefault(in[i+1], new ArrayList<>());
                //u->v map
                u.add(in[i+1]);
                graph.put(in[i],u);
                graph.put(in[i+1],v);
            }
        }
        Map<Character, Integer> isDone= new HashMap<>();
        Map<Character, String> pathMap= new HashMap<>();

        String res="";
        for(char ch:graph.keySet()){
            if(!isDone.containsKey(ch)){
                String temp =dfs(graph,ch, isDone, pathMap);
                if(temp.length()>=res.length()){
                    res=temp;
                }
            }
        }
        return res;
    }

    public String dfs(Map<Character,List<Character>> graph, char u, Map<Character, Integer> isDone, Map<Character, String> pathMap){

        if(isDone.containsKey(u))
            return "";

        isDone.put(u,1);

        int maxChildPathLen=0;
        String maxChildPath="";
        StringBuffer currPath=new StringBuffer();
        currPath.append(u);

        for(char v: graph.get(u)){
            if(pathMap.containsKey(v)){
                currPath.append(pathMap.get(v));
                pathMap.put(u,currPath.toString());
                return currPath.toString();
            }
            if(!isDone.containsKey(v)){
                String childPath = dfs(graph,v,isDone,pathMap);
                if(childPath.length()>=maxChildPathLen){
                    maxChildPathLen=childPath.length();
                    maxChildPath=childPath;
                }
            }
        }

        currPath.append(maxChildPath);
        pathMap.put(u,currPath.toString());
        isDone.put(u,2);
        return currPath.toString();
    }

    public static void main(String[] args) {
        TopSort topSort = new TopSort();
        char input[][]=  {{'A', 'C', 'D'},{'A', 'B', 'E'},{'D', 'F', 'G', 'H'},{'Z', 'X', 'C', 'Q', 'R'}};
        System.out.println(topSort.solution(input));
    }


}

