def find_longest_chain(input_lst):

    d = collections.defaultdict(list)
    for item in input_lst:
        for i in range(len(item)-1):
            curr = item[i]
            d[curr].append(item[i+1])

    def dfs(curr):

        count = 1
        if curr in d:
            for nbr in d[curr]:
                count = max(dfs(nbr)+1, count)
        return count
    max_ans = float('inf')
    for k in d.keys():
        ans = dfs(k)
        max_ans = max(ans, max_ans)
    print(max_ans)


